@page "/courses"
@rendermode InteractiveServer
@inject ICatalogService CatalogService

<PageTitle>Course Catalog — State University</PageTitle>

<h1 class="mb-4">Course Catalog</h1>

<div class="row g-3 mb-4">
    <div class="col-md-5">
        <input type="text" class="form-control" placeholder="Search by title, code, or description…"
               @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="selectedDepartment">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <select class="form-select" @bind="selectedCreditsStr">
            <option value="">All Credits</option>
            <option value="1">1 credit</option>
            <option value="2">2 credits</option>
            <option value="3">3 credits</option>
            <option value="4">4 credits</option>
        </select>
    </div>
</div>

@{
    var results = CatalogService.SearchCourses(searchTerm, selectedDepartment, selectedCredits);
}

<p class="text-muted">Showing @results.Count course(s)</p>

<div class="table-responsive">
    <table class="table table-striped table-hover">
        <thead class="table-dark">
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in results)
            {
                var dept = CatalogService.GetDepartment(course.DepartmentId);
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@dept?.Name</td>
                    <td>@course.Credits</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">View Details</a></td>
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    private List<Department> departments = new();
    private string searchTerm = "";
    private string selectedDepartment = "";
    private string selectedCreditsStr = "";

    private int? selectedCredits => int.TryParse(selectedCreditsStr, out var c) ? c : null;

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
    }
}

@page "/courses/{CourseId}"
@inject ICatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found") — State University</PageTitle>

@if (course == null)
{
    <div class="alert alert-warning">Course not found.</div>
    <a href="courses" class="btn btn-secondary">← Back to Courses</a>
}
else
{
    var dept = CatalogService.GetDepartment(course.DepartmentId);
    var instructor = CatalogService.GetInstructor(course.InstructorId);

    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active">@course.Code</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-md-8">
            <h1>@course.Title</h1>
            <h5 class="text-muted mb-3">@course.Code · @dept?.Name</h5>
            <p class="lead">@course.Description</p>

            <table class="table table-bordered mt-4" style="max-width: 500px;">
                <tbody>
                    <tr><th>Credits</th><td>@course.Credits</td></tr>
                    <tr><th>Schedule</th><td>@course.Schedule</td></tr>
                    <tr><th>Location</th><td>@course.Location</td></tr>
                    @if (course.Prerequisites.Any())
                    {
                        <tr><th>Prerequisites</th><td>@string.Join(", ", course.Prerequisites)</td></tr>
                    }
                </tbody>
            </table>

            <div class="mt-3">
                <a href="enroll" class="btn btn-primary me-2">Enroll in This Course</a>
                <a href="courses" class="btn btn-outline-secondary">← Back to Courses</a>
            </div>
        </div>

        <div class="col-md-4">
            @if (instructor != null)
            {
                <div class="card">
                    <div class="card-body text-center">
                        <div class="bg-secondary text-white rounded-circle d-inline-flex align-items-center justify-content-center mb-3" style="width:80px;height:80px;font-size:2rem;">
                            @instructor.Name[0]
                        </div>
                        <h5 class="card-title">@instructor.Name</h5>
                        <h6 class="card-subtitle mb-2 text-muted">@instructor.Title</h6>
                        <p class="card-text small">@instructor.Bio</p>
                        <a href="mailto:@instructor.Email" class="btn btn-sm btn-outline-secondary">@instructor.Email</a>
                    </div>
                </div>
            }
        </div>
    </div>
}

@code {
    [Parameter]
    public string CourseId { get; set; } = "";

    private Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(CourseId);
    }
}

@page "/enroll"
@inject ICatalogService CatalogService

<PageTitle>Enroll — State University</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

@if (submitted)
{
    var course = CatalogService.GetCourse(Model.CourseId);
    <div class="alert alert-success">
        <h4 class="alert-heading">Enrollment Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong> (ID: @Model.StudentId). Your enrollment request for <strong>@course?.Title (@course?.Code)</strong> has been received.</p>
        <hr />
        <a href="courses" class="btn btn-outline-success me-2">Browse More Courses</a>
        <a href="enroll" class="btn btn-outline-secondary">Submit Another</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-6">
            <EditForm Model="Model" method="post" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Student Name</label>
                    <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
                    <ValidationMessage For="() => Model.StudentName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" />
                    <ValidationMessage For="() => Model.StudentId" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                        <option value="">— Select a course —</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    private List<Course> courses = new();
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
    }

    private void HandleSubmit()
    {
        submitted = CatalogService.SubmitEnrollment(Model);
    }
}

