 using UniversityCourseCatalog.Models;

 namespace UniversityCourseCatalog.Services;

 public class CatalogService : ICatalogService
 {
     private readonly List<Department> _departments;
     private readonly List<Instructor> _instructors;
     private readonly List<Course> _courses;
     private readonly List<EnrollmentRequest> _enrollments = new();

     public CatalogService()
     {
         _departments = new List<Department>
         {
             new() { Id = "cs", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
             new() { Id = "math", Name = "Mathematics", Description = "Exploration of numbers, structures, and mathematical reasoning." },
             new() { Id = "phys", Name = "Physics", Description = "Understanding the fundamental laws governing the natural world." },
             new() { Id = "eng", Name = "English", Description = "Literature, writing, and critical analysis of texts." }
         };

         _instructors = new List<Instructor>
         {
             new() { Id = "inst-1", Name = "Dr. Alice Chen", Title = "Professor", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 papers in top-tier conferences and holds three patents in natural language processing.", Email = "achen@stateuniv.edu" },
             new() { Id = "inst-2", Name = "Dr. Robert Martinez", Title = "Associate Professor", Bio = "Dr. Martinez focuses on software engineering and distributed systems. He spent ten years in industry at major tech companies before joining academia.", Email = "rmartinez@stateuniv.edu" },
             new() { Id = "inst-3", Name = "Dr. Sarah Patel", Title = "Professor", Bio = "Dr. Patel is a number theorist whose research explores prime distribution and cryptographic applications. She is a recipient of the National Science Foundation CAREER Award.", Email = "spatel@stateuniv.edu" },
             new() { Id = "inst-4", Name = "Dr. James Wilson", Title = "Associate Professor", Bio = "Dr. Wilson researches statistical mechanics and quantum computing. He leads the university's Quantum Information Lab.", Email = "jwilson@stateuniv.edu" },
             new() { Id = "inst-5", Name = "Dr. Emily Brooks", Title = "Assistant Professor", Bio = "Dr. Brooks is a scholar of 19th-century American literature with a focus on narrative theory and cultural studies.", Email = "ebrooks@stateuniv.edu" },
             new() { Id = "inst-6", Name = "Dr. Michael Torres", Title = "Professor", Bio = "Dr. Torres specializes in applied mathematics and mathematical modeling. His work has been used in climate science and epidemiology.", Email = "mtorres@stateuniv.edu" }
         };

         _courses = new List<Course>
         {
             // Computer Science
             new() { Id = "cs101", Code = "CS 101", Title = "Introduction to Computer Science", Description = "A broad introduction to the field of computer science covering problem solving, algorithms, data representation, and programming fundamentals using Python.", Credits = 3, DepartmentId = "cs", InstructorId = "inst-1", Schedule = "MWF 10:00–10:50 AM", Location = "Tech Hall 101", Prerequisites = new(), IsFeatured = true },
             new() { Id = "cs201", Code = "CS 201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures including arrays, linked lists, trees, graphs, and hash tables along with algorithm design and complexity analysis.", Credits = 4, DepartmentId = "cs", InstructorId = "inst-2", Schedule = "TTh 1:00–2:20 PM", Location = "Tech Hall 203", Prerequisites = new() { "CS 101" }, IsFeatured = true },
             new() { Id = "cs301", Code = "CS 301", Title = "Database Systems", Description = "Design and implementation of relational database systems, SQL, normalization, indexing, and transaction processing.", Credits = 3, DepartmentId = "cs", InstructorId = "inst-2", Schedule = "MWF 2:00–2:50 PM", Location = "Tech Hall 105", Prerequisites = new() { "CS 201" }, IsFeatured = false },
             new() { Id = "cs401", Code = "CS 401", Title = "Artificial Intelligence", Description = "Foundations of AI including search, knowledge representation, machine learning, neural networks, and natural language processing.", Credits = 4, DepartmentId = "cs", InstructorId = "inst-1", Schedule = "TTh 9:30–10:50 AM", Location = "Tech Hall 301", Prerequisites = new() { "CS 201", "MATH 210" }, IsFeatured = true },

             // Mathematics
             new() { Id = "math101", Code = "MATH 101", Title = "Calculus I", Description = "Limits, continuity, derivatives, and integrals of single-variable functions with applications to science and engineering.", Credits = 4, DepartmentId = "math", InstructorId = "inst-3", Schedule = "MWF 9:00–9:50 AM", Location = "Science Hall 110", Prerequisites = new(), IsFeatured = true },
             new() { Id = "math102", Code = "MATH 102", Title = "Calculus II", Description = "Techniques of integration, sequences, series, parametric equations, and polar coordinates.", Credits = 4, DepartmentId = "math", InstructorId = "inst-3", Schedule = "MWF 11:00–11:50 AM", Location = "Science Hall 110", Prerequisites = new() { "MATH 101" }, IsFeatured = false },
             new() { Id = "math210", Code = "MATH 210", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications to data science and engineering.", Credits = 3, DepartmentId = "math", InstructorId = "inst-6", Schedule = "TTh 11:00 AM–12:20 PM", Location = "Science Hall 205", Prerequisites = new() { "MATH 101" }, IsFeatured = false },
             new() { Id = "math310", Code = "MATH 310", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, regression, and data analysis.", Credits = 3, DepartmentId = "math", InstructorId = "inst-6", Schedule = "MWF 1:00–1:50 PM", Location = "Science Hall 205", Prerequisites = new() { "MATH 102" }, IsFeatured = false },

             // Physics
             new() { Id = "phys101", Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes laboratory sessions with hands-on experiments.", Credits = 4, DepartmentId = "phys", InstructorId = "inst-4", Schedule = "MWF 8:00–8:50 AM", Location = "Physics Building 100", Prerequisites = new() { "MATH 101" }, IsFeatured = true },
             new() { Id = "phys102", Code = "PHYS 102", Title = "General Physics II", Description = "Electricity, magnetism, optics, and modern physics. Includes laboratory sessions.", Credits = 4, DepartmentId = "phys", InstructorId = "inst-4", Schedule = "MWF 10:00–10:50 AM", Location = "Physics Building 100", Prerequisites = new() { "PHYS 101" }, IsFeatured = false },
             new() { Id = "phys301", Code = "PHYS 301", Title = "Quantum Mechanics", Description = "Wave-particle duality, Schrödinger equation, quantum states, and measurement theory.", Credits = 3, DepartmentId = "phys", InstructorId = "inst-4", Schedule = "TTh 2:00–3:20 PM", Location = "Physics Building 210", Prerequisites = new() { "PHYS 102", "MATH 210" }, IsFeatured = false },

             // English
             new() { Id = "eng101", Code = "ENG 101", Title = "Composition and Rhetoric", Description = "Fundamentals of academic writing, argumentation, research methods, and critical reading.", Credits = 3, DepartmentId = "eng", InstructorId = "inst-5", Schedule = "MWF 9:00–9:50 AM", Location = "Humanities Hall 101", Prerequisites = new(), IsFeatured = false },
             new() { Id = "eng201", Code = "ENG 201", Title = "American Literature Survey", Description = "A survey of American literature from the colonial period to the present, examining major authors and literary movements.", Credits = 3, DepartmentId = "eng", InstructorId = "inst-5", Schedule = "TTh 10:00–11:20 AM", Location = "Humanities Hall 203", Prerequisites = new() { "ENG 101" }, IsFeatured = true },
             new() { Id = "eng310", Code = "ENG 310", Title = "Creative Writing Workshop", Description = "Workshop-based course in fiction and poetry writing with peer review and revision strategies.", Credits = 3, DepartmentId = "eng", InstructorId = "inst-5", Schedule = "TTh 3:30–4:50 PM", Location = "Humanities Hall 105", Prerequisites = new() { "ENG 101" }, IsFeatured = false }
         };
     }

     public List<Department> GetDepartments() => _departments;

     public Department? GetDepartment(string id) =>
         _departments.FirstOrDefault(d => d.Id == id);

     public List<Course> GetCourses() => _courses;

     public List<Course> SearchCourses(string? searchTerm, string? departmentId, int? credits)
     {
         var query = _courses.AsEnumerable();

         if (!string.IsNullOrWhiteSpace(searchTerm))
         {
             var term = searchTerm.Trim();
             query = query.Where(c =>
                 c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                 c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                 c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
         }

         if (!string.IsNullOrWhiteSpace(departmentId))
         {
             query = query.Where(c => c.DepartmentId == departmentId);
         }

         if (credits.HasValue)
         {
             query = query.Where(c => c.Credits == credits.Value);
         }

         return query.ToList();
     }

     public Course? GetCourse(string id) =>
         _courses.FirstOrDefault(c => c.Id == id);

     public List<Course> GetFeaturedCourses() =>
         _courses.Where(c => c.IsFeatured).ToList();

     public List<Course> GetCoursesByDepartment(string departmentId) =>
         _courses.Where(c => c.DepartmentId == departmentId).ToList();

     public Instructor? GetInstructor(string id) =>
         _instructors.FirstOrDefault(i => i.Id == id);

     public bool SubmitEnrollment(EnrollmentRequest request)
     {
         if (string.IsNullOrWhiteSpace(request.StudentName) ||
             string.IsNullOrWhiteSpace(request.StudentId) ||
             string.IsNullOrWhiteSpace(request.CourseId))
         {
             return false;
         }

         var course = GetCourse(request.CourseId);
         if (course == null) return false;

         _enrollments.Add(request);
         return true;
     }
 }

