 @page "/courses/{CourseId}"
 @inject ICatalogService CatalogService

 <PageTitle>@(course?.Title ?? "Course Not Found") — State University</PageTitle>

 @if (course == null)
 {
     <div class="alert alert-warning">Course not found.</div>
     <a href="courses" class="btn btn-secondary">← Back to Courses</a>
 }
 else
 {
     var dept = CatalogService.GetDepartment(course.DepartmentId);
     var instructor = CatalogService.GetInstructor(course.InstructorId);

     <nav aria-label="breadcrumb" class="mb-3">
         <ol class="breadcrumb">
             <li class="breadcrumb-item"><a href="courses">Courses</a></li>
             <li class="breadcrumb-item active">@course.Code</li>
         </ol>
     </nav>

     <div class="row">
         <div class="col-md-8">
             <h1>@course.Title</h1>
             <h5 class="text-muted mb-3">@course.Code · @dept?.Name</h5>
             <p class="lead">@course.Description</p>

             <table class="table table-bordered mt-4" style="max-width: 500px;">
                 <tbody>
                     <tr><th>Credits</th><td>@course.Credits</td></tr>
                     <tr><th>Schedule</th><td>@course.Schedule</td></tr>
                     <tr><th>Location</th><td>@course.Location</td></tr>
                     @if (course.Prerequisites.Any())
                     {
                         <tr><th>Prerequisites</th><td>@string.Join(", ", course.Prerequisites)</td></tr>
                     }
                 </tbody>
             </table>

             <div class="mt-3">
                 <a href="enroll" class="btn btn-primary me-2">Enroll in This Course</a>
                 <a href="courses" class="btn btn-outline-secondary">← Back to Courses</a>
             </div>
         </div>

         <div class="col-md-4">
             @if (instructor != null)
             {
                 <div class="card">
                     <div class="card-body text-center">
                         <div class="bg-secondary text-white rounded-circle d-inline-flex align-items-center justify-content-center mb-3" style="width:80px;height:80px;font-size:2rem;">
                             @instructor.Name[0]
                         </div>
                         <h5 class="card-title">@instructor.Name</h5>
                         <h6 class="card-subtitle mb-2 text-muted">@instructor.Title</h6>
                         <p class="card-text small">@instructor.Bio</p>
                         <a href="mailto:@instructor.Email" class="btn btn-sm btn-outline-secondary">@instructor.Email</a>
                     </div>
                 </div>
             }
         </div>
     </div>
 }

 @code {
     [Parameter]
     public string CourseId { get; set; } = "";

     private Course? course;

     protected override void OnInitialized()
     {
         course = CatalogService.GetCourse(CourseId);
     }
 }

